-- ─────────────────────────────────────────────────────────────────────────────
-- Migration 0011_guides.sql
-- Page 16 — Guides Hub + Guide Page (MVP).
--
-- `guides` is the evergreen content engine, intentionally separate from
-- `blog_posts` (timely news, NewsArticle JSON-LD): guides are step-by-step,
-- get *updated* rather than re-dated, and drive `HowTo`/`Article` JSON-LD.
--
-- Content model (MVP, no Admin CMS in this task — see docs/design/16-guides-handoff.md
-- D2): `body` stores a typed JSON block array per locale (GuideBlock[] —
-- lib/guides/types.ts), never raw/rich HTML. There is therefore no
-- server-side HTML sanitization concern for this table — every row is
-- written by a trusted seed script / the service-role client, never by
-- end-user or CMS input.
--
-- RLS design:
--   - Public SELECT is restricted to `status = 'published'` rows only, for
--     any caller (including anonymous/anon-key). Matches the task's
--     explicit requirement ("public SELECT for published guides").
--   - No INSERT/UPDATE/DELETE policy is created for the anon/authenticated
--     roles at all — this table is written exclusively via the
--     service-role client (the seed script / a future Admin CMS), which
--     bypasses RLS by design. Mirrors 0010_home_value_estimates.sql's
--     "service-role-only writer" precedent; here there is no
--     authenticated-write use case at all, so no INSERT/UPDATE policy is
--     needed (the task brief: "INSERT/UPDATE restricted to service role").
-- ─────────────────────────────────────────────────────────────────────────────

CREATE TABLE IF NOT EXISTS guides (
  id                  UUID           PRIMARY KEY DEFAULT gen_random_uuid(),
  slug                TEXT           NOT NULL UNIQUE,
  category            TEXT           NOT NULL
                                        CHECK (category IN ('buyer', 'seller', 'renter', 'finance')),
  status              TEXT           NOT NULL DEFAULT 'draft'
                                        CHECK (status IN ('draft', 'published')),
  featured            BOOLEAN        NOT NULL DEFAULT FALSE,

  -- Per-locale text, keyed by locale code ('hy' | 'ru' | 'en'); a guide need
  -- not carry all three keys (see lib/guides/content.ts's fallback chain).
  title               JSONB          NOT NULL,
  excerpt             JSONB          NOT NULL,
  -- Each locale key maps to a GuideBlock[] (lib/guides/types.ts) — never raw
  -- HTML (no dangerouslySetInnerHTML anywhere in the guides feature).
  body                JSONB          NOT NULL,
  -- Precomputed at seed time from that locale's `heading` blocks:
  -- { id, text, level }[] per locale. Not recomputed at request time.
  toc                 JSONB          NOT NULL DEFAULT '{}'::jsonb,

  cover_url           TEXT,
  author_name         TEXT,
  author_credentials  TEXT,

  reading_time        INTEGER        NOT NULL DEFAULT 5 CHECK (reading_time > 0),
  step_count          INTEGER        NOT NULL DEFAULT 0 CHECK (step_count >= 0),

  created_at          TIMESTAMPTZ    NOT NULL DEFAULT NOW(),
  updated_at          TIMESTAMPTZ    NOT NULL DEFAULT NOW()
);

CREATE INDEX IF NOT EXISTS guides_category_status_idx ON guides (category, status);
CREATE INDEX IF NOT EXISTS guides_updated_at_idx ON guides (updated_at DESC);
CREATE INDEX IF NOT EXISTS guides_featured_idx ON guides (featured) WHERE status = 'published';

ALTER TABLE guides ENABLE ROW LEVEL SECURITY;

CREATE POLICY "guides: published are public"
  ON guides
  FOR SELECT
  USING (status = 'published');

-- ─────────────────────────────────────────────────────────────────────────────
-- Seed data — a handful of sample guides for dev/demo (task brief: "seed a
-- handful of sample guides via migration/seed script for dev/demo"; no Admin
-- CMS editor in this task). Reference/demo content, not user-tied, so it is
-- seeded here rather than in supabase/seed.sql — same precedent as
-- 0009_plans.sql's reference-data seed.
--
-- Covers all 4 canonical categories (buyer/seller/renter/finance) and
-- includes `why-an-agent`, matching a slug already hardcoded in
-- components/layout/Header.tsx, so that nav link is never a 404. 3 guides are
-- flagged `featured = true` (the hub's "Most popular guides" section). 3
-- guides are seeded with only hy/en (no ru) to exercise the per-locale
-- fallback chain (lib/guides/content.ts's pickLocalized) without crashing.
-- ─────────────────────────────────────────────────────────────────────────────

