  (
    'down-payment-explained', 'finance', 'published', false,
    $j${"en":"Down Payment Explained","hy":"Կանխավճարը բացատրված"}$j$::jsonb,
    $j${"en":"What a down payment is, how much you need, and practical ways to save for it faster.","hy":"Ինչ է կանխավճարը, որքան է անհրաժեշտ, և ինչպես ավելի արագ խնայել դրա համար։"}$j$::jsonb,
    $j${"en":[{"kind":"paragraph","text":"The down payment is often the biggest hurdle for first-time buyers. This guide explains what it is, how much you'll likely need, and how to save for it faster."},{"kind":"heading","id":"what-is-a-down-payment","level":2,"text":"Step 1 — What is a down payment"},{"kind":"paragraph","text":"A down payment is the portion of a home's price you pay upfront in cash, with the rest covered by a mortgage. It reduces the amount you borrow, which lowers your monthly payment and the total interest you pay over time."},{"kind":"paragraph","text":"Lenders also see a larger down payment as a sign of lower risk, which can help you qualify for a better interest rate."},{"kind":"tool_cta","tool":"mortgage","label":"Calculate my mortgage"},{"kind":"heading","id":"how-much-do-you-need","level":2,"text":"Step 2 — How much do you need"},{"kind":"paragraph","text":"Most lenders require a down payment of 10-20% of the purchase price, though the exact amount depends on the bank and loan program. On a property worth 30,000,000 AMD, that means anywhere from 3,000,000 to 6,000,000 AMD upfront."},{"kind":"info","text":"💡 Tip: Use a mortgage calculator to see how different down payment amounts affect your monthly payment before you commit to a number."},{"kind":"heading","id":"ways-to-save-faster","level":2,"text":"Step 3 — Ways to save faster"},{"kind":"paragraph","text":"Automate a fixed transfer to a separate savings account every payday so the money is set aside before you can spend it. Cutting a few discretionary expenses and redirecting bonuses or tax refunds can speed things up significantly."},{"kind":"paragraph","text":"Some buyers also receive help from family or use government first-time buyer programs where available."},{"kind":"warning","text":"⚠️ Caution: Avoid keeping your down payment savings in risky investments — a market downturn right before you buy could shrink the amount you have available."},{"kind":"list","items":["Open a dedicated savings account","Automate monthly transfers","Cut non-essential spending temporarily","Redirect bonuses and tax refunds","Ask about first-time buyer assistance programs"]}],"hy":[{"kind":"paragraph","text":"Կանխավճարը հաճախ ամենամեծ խոչընդոտն է առաջին անգամ գնողների համար։ Այս ուղեցույցը բացատրում է, թե ինչ է այն, ինչքան կարող է անհրաժեշտ լինել, և ինչպես ավելի արագ կուտակել այն։"},{"kind":"heading","id":"what-is-a-down-payment","level":2,"text":"Քայլ 1 — Ինչ է կանխավճարը"},{"kind":"paragraph","text":"Կանխավճարը տան գնի այն մասն է, որը դուք վճարում եք նախապես կանխիկ, իսկ մնացածը ծածկվում է հիփոթեքով։ Այն նվազեցնում է փոխառվող գումարը, ինչը իջեցնում է ամսական վճարումը և ընդհանուր վճարվող տոկոսը ժամանակի ընթացքում։"},{"kind":"paragraph","text":"Վարկատուները նաև ավելի մեծ կանխավճարը դիտարկում են որպես ցածր ռիսկի նշան, ինչը կարող է օգնել ձեզ ստանալ ավելի լավ տոկոսադրույք։"},{"kind":"tool_cta","tool":"mortgage","label":"Հաշվարկել իմ հիփոթեքը"},{"kind":"heading","id":"how-much-do-you-need","level":2,"text":"Քայլ 2 — Որքան է անհրաժեշտ"},{"kind":"paragraph","text":"Վարկատուների մեծ մասը պահանջում է գնման գնի 10-20%-ի չափով կանխավճար, թեև ճշգրիտ չափը կախված է բանկից և վարկային ծրագրից։ 30,000,000 դրամ արժողությամբ գույքի համար դա նշանակում է 3,000,000-ից մինչև 6,000,000 դրամ նախապես վճարում։"},{"kind":"info","text":"💡 Խորհուրդ. Օգտագործեք հիփոթեքի հաշվիչը՝ տեսնելու համար, թե ինչպես են տարբեր կանխավճարային գումարները ազդում ձեր ամսական վճարման վրա, նախքան վերջնական թիվ ընտրելը։"},{"kind":"heading","id":"ways-to-save-faster","level":2,"text":"Քայլ 3 — Ինչպես ավելի արագ խնայել"},{"kind":"paragraph","text":"Յուրաքանչյուր աշխատավարձ ստանալուց հետո ավտոմատացրեք ֆիքսված գումարի փոխանցումն առանձին խնայողական հաշվին, որպեսզի գումարը կողքի դրվի դեռ ծախսելուց առաջ։ Մի քանի ոչ անհրաժեշտ ծախսերի կրճատումը և հավելավճարների կամ հարկային վերադարձների ուղղորդումը կարող են զգալիորեն արագացնել գործընթացը։"},{"kind":"paragraph","text":"Որոշ գնորդներ նաև օգնություն են ստանում ընտանիքից կամ օգտվում պետական՝ առաջին անգամ գնողների ծրագրերից, եթե այդպիսիք հասանելի են։"},{"kind":"warning","text":"⚠️ Ուշադրություն. Խուսափեք կանխավճարի համար նախատեսված խնայողությունները ռիսկային ներդրումներում պահելուց․ շուկայի անկումը գնման նախաշեմին կարող է փոքրացնել ձեր հասանելի գումարը։"},{"kind":"list","items":["Բացեք առանձին խնայողական հաշիվ","Ավտոմատացրեք ամսական փոխանցումները","Ժամանակավորապես կրճատեք ոչ անհրաժեշտ ծախսերը","Ուղղորդեք հավելավճարներն ու հարկային վերադարձները","Հետաքրքրվեք առաջին անգամ գնողների աջակցության ծրագրերով"]}]}$j$::jsonb,
    $j${"en":[{"id":"what-is-a-down-payment","text":"Step 1 — What is a down payment","level":2},{"id":"how-much-do-you-need","text":"Step 2 — How much do you need","level":2},{"id":"ways-to-save-faster","text":"Step 3 — Ways to save faster","level":2}],"hy":[{"id":"what-is-a-down-payment","text":"Քայլ 1 — Ինչ է կանխավճարը","level":2},{"id":"how-much-do-you-need","text":"Քայլ 2 — Որքան է անհրաժեշտ","level":2},{"id":"ways-to-save-faster","text":"Քայլ 3 — Ինչպես ավելի արագ խնայել","level":2}]}$j$::jsonb,
